import { describe, it, expect, vi, beforeEach } from "vitest";

const mocks = vi.hoisted(() => {
  const mockReturning = vi.fn();
  const mockValues = vi.fn(() => ({ returning: mockReturning }));
  const mockInsert = vi.fn(() => ({ values: mockValues }));
  const mockSelect = vi.fn();
  const mockFrom = vi.fn();
  const mockWhere = vi.fn();
  const mockRequireDocumentOwner = vi.fn();

  return {
    mockInsert,
    mockValues,
    mockReturning,
    mockSelect,
    mockFrom,
    mockWhere,
    mockRequireDocumentOwner,
  };
});

vi.mock("@/auth", () => ({
  auth: vi.fn(),
  signIn: vi.fn(),
  signOut: vi.fn(),
  handlers: { GET: vi.fn(), POST: vi.fn() },
}));

vi.mock("@/lib/db", () => ({
  db: {
    insert: mocks.mockInsert,
    select: mocks.mockSelect,
  },
}));

vi.mock("@/lib/db/schema", () => ({
  aiInteractions: {
    id: "id",
    documentId: "document_id",
    sessionId: "session_id",
    mode: "mode",
    prompt: "prompt",
    selectedText: "selected_text",
    response: "response",
    action: "action",
    documentDiff: "document_diff",
    charactersInserted: "characters_inserted",
    provider: "provider",
    model: "model",
    createdAt: "created_at",
  },
  writingSessions: {
    id: "id",
    documentId: "document_id",
    userId: "user_id",
  },
}));

vi.mock("@/lib/auth/authorize", () => ({
  requireDocumentOwner: mocks.mockRequireDocumentOwner,
}));

vi.mock("drizzle-orm", () => ({
  and: vi.fn((...conds: unknown[]) => ({ _and: conds })),
  eq: vi.fn((col: unknown, val: unknown) => ({ _eq: { col, val } })),
}));

import { logAIInteraction } from "./ai-interactions";

describe("logAIInteraction", () => {
  beforeEach(() => {
    vi.clearAllMocks();

    mocks.mockRequireDocumentOwner.mockResolvedValue({
      user: { id: "user-1" },
      document: { id: "doc-1", userId: "user-1" },
    });

    mocks.mockInsert.mockReturnValue({ values: mocks.mockValues });
    mocks.mockValues.mockReturnValue({ returning: mocks.mockReturning });
    mocks.mockReturning.mockResolvedValue([
      {
        id: "ai-1",
        documentId: "doc-1",
        mode: "inline",
        prompt: "Improve this",
        response: "Here is improved text",
        action: "accepted",
        provider: "anthropic",
        model: "claude-sonnet-4-5-20250929",
      },
    ]);

    mocks.mockWhere.mockResolvedValue([{ id: "session-1" }]);
    mocks.mockFrom.mockReturnValue({ where: mocks.mockWhere });
    mocks.mockSelect.mockReturnValue({ from: mocks.mockFrom });
  });

  it("should write full interaction record to ai_interactions table", async () => {
    const result = await logAIInteraction({
      documentId: "doc-1",
      mode: "inline",
      prompt: "Improve this",
      selectedText: "original text",
      response: "Here is improved text",
      action: "accepted",
      provider: "anthropic",
      model: "claude-sonnet-4-5-20250929",
    });

    expect(mocks.mockRequireDocumentOwner).toHaveBeenCalledWith("doc-1");
    expect(mocks.mockInsert).toHaveBeenCalled();
    expect(mocks.mockValues).toHaveBeenCalledWith(
      expect.objectContaining({
        documentId: "doc-1",
        mode: "inline",
        prompt: "Improve this",
        selectedText: "original text",
        response: "Here is improved text",
        action: "accepted",
        provider: "anthropic",
        model: "claude-sonnet-4-5-20250929",
      })
    );
    expect(result).toHaveProperty("id", "ai-1");
  });

  it("should persist sourceId as interaction id when provided", async () => {
    const sourceId = "8ed7bd6e-4b6b-43ef-bd8f-279891763f8a";

    await logAIInteraction({
      sourceId,
      documentId: "doc-1",
      mode: "inline",
      prompt: "Improve this",
      response: "Here is improved text",
      action: "accepted",
      provider: "anthropic",
      model: "claude-sonnet-4-5-20250929",
    });

    expect(mocks.mockValues).toHaveBeenCalledWith(
      expect.objectContaining({
        id: sourceId,
      })
    );
  });

  it("should reject invalid sourceId values", async () => {
    await expect(
      logAIInteraction({
        sourceId: "not-a-uuid",
        documentId: "doc-1",
        mode: "inline",
        prompt: "Improve this",
        response: "Here is improved text",
        action: "accepted",
        provider: "anthropic",
        model: "claude-sonnet-4-5-20250929",
      })
    ).rejects.toThrow("Invalid sourceId");

    expect(mocks.mockInsert).not.toHaveBeenCalled();
  });

  it("should require valid sessionId when provided", async () => {
    mocks.mockWhere.mockResolvedValue([]);

    await expect(
      logAIInteraction({
        documentId: "doc-1",
        sessionId: "session-1",
        mode: "inline",
        prompt: "Improve this",
        response: "Here is improved text",
        action: "accepted",
        provider: "anthropic",
        model: "claude-sonnet-4-5-20250929",
      })
    ).rejects.toThrow("Not found");

    expect(mocks.mockInsert).not.toHaveBeenCalled();
  });

  it("should be append-only with no update or delete operations", async () => {
    // logAIInteraction only uses insert — verify no update/delete methods exist
    await logAIInteraction({
      documentId: "doc-1",
      mode: "side_panel",
      prompt: "Help me brainstorm",
      response: "Sure, here are ideas",
      action: "accepted",
      provider: "openai",
      model: "gpt-4o",
    });

    // Only insert is called, never update or delete
    expect(mocks.mockInsert).toHaveBeenCalledTimes(1);
  });

  it("should default charactersInserted to 0 when not provided", async () => {
    await logAIInteraction({
      documentId: "doc-1",
      mode: "freeform",
      prompt: "Write something",
      response: "Here you go",
      action: "accepted",
      provider: "anthropic",
      model: "",
    });

    expect(mocks.mockValues).toHaveBeenCalledWith(
      expect.objectContaining({
        charactersInserted: 0,
      })
    );
  });

  it("should require authentication before logging", async () => {
    mocks.mockRequireDocumentOwner.mockRejectedValue(
      new Error("Unauthorized")
    );

    await expect(
      logAIInteraction({
        documentId: "doc-1",
        mode: "inline",
        prompt: "test",
        response: "test",
        action: "accepted",
        provider: "anthropic",
        model: "",
      })
    ).rejects.toThrow("Unauthorized");

    expect(mocks.mockInsert).not.toHaveBeenCalled();
  });
});

"use server";

import { db } from "@/lib/db";
import { aiInteractions, writingSessions } from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import { and, eq } from "drizzle-orm";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

interface LogAIInteractionData {
  sourceId?: string;
  documentId: string;
  sessionId?: string;
  mode: string;
  prompt: string;
  selectedText?: string;
  response: string;
  action: string;
  documentDiff?: unknown;
  charactersInserted?: number;
  provider: string;
  model: string;
}

export async function logAIInteraction(data: LogAIInteractionData) {
  if (data.sourceId && !UUID_RE.test(data.sourceId)) {
    throw new Error("Invalid sourceId");
  }

  const { user } = await requireDocumentOwner(data.documentId);

  if (data.sessionId) {
    const [session] = await db
      .select({ id: writingSessions.id })
      .from(writingSessions)
      .where(
        and(
          eq(writingSessions.id, data.sessionId),
          eq(writingSessions.userId, user.id),
          eq(writingSessions.documentId, data.documentId)
        )
      );

    if (!session) {
      throw new Error("Not found");
    }
  }

  const [interaction] = await db
    .insert(aiInteractions)
    .values({
      ...(data.sourceId ? { id: data.sourceId } : {}),
      documentId: data.documentId,
      sessionId: data.sessionId,
      mode: data.mode,
      prompt: data.prompt,
      selectedText: data.selectedText,
      response: data.response,
      action: data.action,
      documentDiff: data.documentDiff,
      charactersInserted: data.charactersInserted ?? 0,
      provider: data.provider,
      model: data.model,
    })
    .returning();

  return interaction;
}

