import { db } from "@/lib/db";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import {
  calculateMetrics,
  estimateRetainedAiCharactersFromAcceptedResponses,
} from "@/lib/metrics";

describe("generateBadge", () => {
  beforeEach(() => {
    vi.clearAllMocks();

    // Setup default db mock returns
    const mockDb = db as unknown as Record<string, ReturnType<typeof vi.fn>>;

    // select().from().where() returns audit trail data
    let selectCallCount = 0;
    mockDb.where.mockImplementation(() => {
      selectCallCount++;
      // First 4 calls are for fetching audit trail data
      if (selectCallCount <= 4) {
        return Promise.resolve([]);
      }
      return Promise.resolve([]);
    });

    // insert().values().returning() returns the created badge
    mockDb.returning.mockImplementation(() =>
      Promise.resolve([
        {
          id: "badge-1",
          verificationId: "abc123def456ghi789012",
          documentTitle: "Test Document",
          stats: {
            ai_percentage: 12,
            external_paste_percentage: 5,
            interaction_count: 0,
            session_count: 0,
            total_active_seconds: 0,
          },
          createdAt: new Date(),
        },
      ])
    );
  });

  it("should create badge record with frozen document text and audit trail", async () => {
    const result = await generateBadge("doc-1");

    expect(requireDocumentOwner).toHaveBeenCalledWith("doc-1");
    expect(result).toBeDefined();
    expect(result.verificationId).toBeDefined();
  });

  it("should use nanoid(21) for verification_id — 21 characters, unguessable", async () => {
    const { nanoid } = await import("nanoid");
    await generateBadge("doc-1");

    expect(nanoid).toHaveBeenCalledWith(21);
  });

  it("should include stats with ai_percentage, external_paste_percentage, interaction_count, session_count, total_active_seconds", async () => {
    const mockDb = db as unknown as Record<string, ReturnType<typeof vi.fn>>;
    mockDb.returning.mockImplementation(() =>
      Promise.resolve([
        {
          id: "badge-1",
          verificationId: "abc123def456ghi789012",
          stats: {
            ai_percentage: 12,
            external_paste_percentage: 5,
            interaction_count: 0,
            session_count: 0,
            total_active_seconds: 0,
          },
        },
      ])
    );

    const result = await generateBadge("doc-1");
    expect(result.stats).toBeDefined();
    expect(result.stats).toHaveProperty("ai_percentage");
    expect(result.stats).toHaveProperty("external_paste_percentage");
    expect(result.stats).toHaveProperty("interaction_count");
    expect(result.stats).toHaveProperty("session_count");
    expect(result.stats).toHaveProperty("total_active_seconds");
  });

  it("should be insert-only — no update or delete permitted", async () => {
    const mockDb = db as unknown as Record<string, ReturnType<typeof vi.fn>>;

    await generateBadge("doc-1");

    // Verify only insert was called, not update or delete
    expect(mockDb.insert).toHaveBeenCalled();
    // The function should not expose update or delete operations
  });

  it("should reject non-owners with authorization error", async () => {
    vi.mocked(requireDocumentOwner).mockRejectedValueOnce(
      new Error("Forbidden")
    );

    await expect(generateBadge("doc-1")).rejects.toThrow("Forbidden");
  });

  it("should return verificationId, badgeHtml, and badgeMarkdown snippets", async () => {
    const result = await generateBadge("doc-1");

    expect(result.verificationId).toBe("abc123def456ghi789012");
    expect(result.badgeHtml).toBeDefined();
    expect(result.badgeHtml).toContain("abc123def456ghi789012");
    expect(result.badgeMarkdown).toBeDefined();
    expect(result.badgeMarkdown).toContain("abc123def456ghi789012");
  });

  it("should use fallback AI estimation when mark-based AI percentage is zero", async () => {
    const mockDb = db as unknown as Record<string, ReturnType<typeof vi.fn>>;
    mockDb.where
      .mockResolvedValueOnce([
        {
          mode: "inline",
          action: "accepted",
          response: "Hello world",
          charactersInserted: 11,
          provider: "anthropic",
          model: "claude",
          prompt: "rewrite",
          selectedText: "hi",
          createdAt: new Date(),
        },
      ])
      .mockResolvedValueOnce([])
      .mockResolvedValueOnce([])
      .mockResolvedValueOnce([]);

    vi.mocked(calculateMetrics).mockReturnValueOnce({
      ai_percentage: 0,
      external_paste_percentage: 0,
      total_characters: 100,
    });
    vi.mocked(estimateRetainedAiCharactersFromAcceptedResponses).mockReturnValueOnce(40);

    await generateBadge("doc-1");

    expect(mockDb.values).toHaveBeenCalledWith(
      expect.objectContaining({
        stats: expect.objectContaining({
          ai_percentage: 40,
        }),
      })
    );
  });
});

"use server";

import { db } from "@/lib/db";
import {
  badges,
  aiInteractions,
  pasteEvents,
  writingSessions,
  revisions,
  chatThreads,
} from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import {
  calculateMetrics,
  estimateRetainedAiCharactersFromAcceptedResponses,
} from "@/lib/metrics";
import { extractPlainText } from "@/lib/tiptap-utils";
import { generateBadgeHtml, generateBadgeMarkdown } from "@/lib/badge-snippets";
import { nanoid } from "nanoid";
import { eq } from "drizzle-orm";
import { revalidatePath } from "next/cache";

export async function generateBadge(documentId: string) {
  const { document } = await requireDocumentOwner(documentId);

  // Fetch audit trail data
  const [interactions, pastes, sessions, documentRevisions, threads] = await Promise.all([
    db
      .select()
      .from(aiInteractions)
      .where(eq(aiInteractions.documentId, documentId)),
    db
      .select()
      .from(pasteEvents)
      .where(eq(pasteEvents.documentId, documentId)),
    db
      .select()
      .from(writingSessions)
      .where(eq(writingSessions.documentId, documentId)),
    db
      .select()
      .from(revisions)
      .where(eq(revisions.documentId, documentId)),
    db
      .select({
        mode: chatThreads.mode,
        summary: chatThreads.summary,
        messageCount: chatThreads.messageCount,
        createdAt: chatThreads.createdAt,
      })
      .from(chatThreads)
      .where(eq(chatThreads.documentId, documentId)),
  ]);

  // Extract plain text and calculate metrics
  const content = document.content as Parameters<typeof extractPlainText>[0];
  const documentText = extractPlainText(content);
  const metrics = calculateMetrics(content);
  const fallbackAiChars = estimateRetainedAiCharactersFromAcceptedResponses(
    documentText,
    interactions
  );
  const fallbackAiPct =
    metrics.total_characters > 0
      ? Math.floor(
          (Math.min(fallbackAiChars, metrics.total_characters) /
            metrics.total_characters) *
            100
        )
      : 0;
  const resolvedAiPercentage = Math.max(metrics.ai_percentage, fallbackAiPct);

  // Calculate stats
  const totalActiveSeconds = sessions.reduce(
    (sum, s) => sum + (s.activeSeconds ?? 0),
    0
  );

  const stats = {
    ai_percentage: resolvedAiPercentage,
    external_paste_percentage: metrics.external_paste_percentage,
    interaction_count: interactions.length,
    session_count: sessions.length,
    total_active_seconds: totalActiveSeconds,
    total_characters: metrics.total_characters,
    chat_thread_count: threads.length,
  };

  // Generate verification ID
  const verificationId = nanoid(21);

  // Freeze the audit trail
  const auditTrail = {
    ai_interactions: interactions.map((i) => ({
      sourceId: i.id,
      mode: i.mode,
      prompt: i.prompt,
      selectedText: i.selectedText,
      response: i.response,
      action: i.action,
      provider: i.provider,
      model: i.model,
      createdAt: i.createdAt,
    })),
    paste_events: pastes.map((p) => ({
      sourceId: p.id,
      sourceType: p.sourceType,
      characterCount: p.characterCount,
      createdAt: p.createdAt,
    })),
    writing_sessions: sessions.map((s) => ({
      startedAt: s.startedAt,
      endedAt: s.endedAt,
      activeSeconds: s.activeSeconds,
    })),
    revisions: documentRevisions.map((r) => ({
      trigger: r.trigger,
      createdAt: r.createdAt,
    })),
    chat_threads: threads.map((t) => ({
      mode: t.mode,
      summary: t.summary,
      messageCount: t.messageCount,
      createdAt: t.createdAt,
    })),
  };

  // Insert badge record (insert-only, no update or delete)
  const [badge] = await db
    .insert(badges)
    .values({
      documentId,
      verificationId,
      documentTitle: document.title,
      documentText,
      documentContent: document.content,
      auditTrail,
      stats,
    })
    .returning();

  // Generate embed snippets
  const badgeHtml = generateBadgeHtml(verificationId, resolvedAiPercentage);
  const badgeMarkdown = generateBadgeMarkdown(
    verificationId,
    resolvedAiPercentage
  );

  return {
    ...badge,
    badgeHtml,
    badgeMarkdown,
  };
}

export async function takedownBadge(badgeId: string, reason?: string) {
  const [badge] = await db
    .select()
    .from(badges)
    .where(eq(badges.id, badgeId));

  if (!badge) throw new Error("Badge not found");

  // Verify ownership through document
  await requireDocumentOwner(badge.documentId);

  await db
    .update(badges)
    .set({
      isTakenDown: true,
      takedownReason: reason ?? null,
    })
    .where(eq(badges.id, badgeId));

  // Trigger on-demand revalidation for the verification page and badge image
  revalidatePath(`/verify/${badge.verificationId}`);
  revalidatePath(`/api/badges/${badge.verificationId}/image`);
}

"use server";

import { db } from "@/lib/db";
import { chatThreads } from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import { eq, and, desc } from "drizzle-orm";

// Whitelist of allowed summary keys to prevent arbitrary client data
// from flowing into the public badge audit trail.
const ALLOWED_SUMMARY_KEYS = new Set([
  "messageCount",
  "durationMinutes",
  "category",
  "provider",
  "model",
  "tokenCount",
]);

function sanitizeSummary(
  raw: Record<string, unknown> | undefined
): Record<string, unknown> | undefined {
  if (!raw) return undefined;
  const clean: Record<string, unknown> = {};
  for (const key of Object.keys(raw)) {
    if (!ALLOWED_SUMMARY_KEYS.has(key)) continue;
    const val = raw[key];
    if (typeof val === "string" || typeof val === "number") {
      clean[key] = val;
    }
  }
  return clean;
}

export async function getChatThreads(documentId: string) {
  await requireDocumentOwner(documentId);

  return db
    .select({
      id: chatThreads.id,
      title: chatThreads.title,
      messageCount: chatThreads.messageCount,
      updatedAt: chatThreads.updatedAt,
    })
    .from(chatThreads)
    .where(eq(chatThreads.documentId, documentId))
    .orderBy(desc(chatThreads.updatedAt));
}

export async function getChatThread(threadId: string) {
  const [thread] = await db
    .select()
    .from(chatThreads)
    .where(eq(chatThreads.id, threadId));

  if (!thread) throw new Error("Not found");

  await requireDocumentOwner(thread.documentId);

  return thread;
}

export async function saveChatThread(data: {
  documentId: string;
  threadId?: string;
  title?: string;
  messages: unknown[];
  messageCount: number;
  summary?: Record<string, unknown>;
}) {
  const { user } = await requireDocumentOwner(data.documentId);
  const safeSummary = sanitizeSummary(data.summary);

  if (data.threadId) {
    // Update existing thread — scope to documentId + userId to prevent
    // cross-user updates if someone guesses a thread ID.
    const [updated] = await db
      .update(chatThreads)
      .set({
        title: data.title,
        messages: data.messages,
        messageCount: data.messageCount,
        summary: safeSummary,
        updatedAt: new Date(),
      })
      .where(
        and(
          eq(chatThreads.id, data.threadId),
          eq(chatThreads.documentId, data.documentId),
          eq(chatThreads.userId, user.id!)
        )
      )
      .returning();

    if (!updated) throw new Error("Not found");

    return updated;
  }

  // Create new thread
  const [created] = await db
    .insert(chatThreads)
    .values({
      documentId: data.documentId,
      userId: user.id!,
      title: data.title ?? "New conversation",
      messages: data.messages,
      messageCount: data.messageCount,
      summary: safeSummary,
    })
    .returning();

  return created;
}

export async function deleteChatThread(threadId: string) {
  const [thread] = await db
    .select()
    .from(chatThreads)
    .where(eq(chatThreads.id, threadId));

  if (!thread) throw new Error("Not found");

  await requireDocumentOwner(thread.documentId);

  await db.delete(chatThreads).where(eq(chatThreads.id, threadId));
}

import { describe, it, expect, vi, beforeEach } from "vitest";

/**
 * Cross-user security tests.
 *
 * These tests verify that mutation actions reject attempts by
 * non-owners to write to documents they don't own.
 */

const mocks = vi.hoisted(() => ({
  mockRequireDocumentOwner: vi.fn(),
  mockRequireAuth: vi.fn(),
  mockInsert: vi.fn(),
  mockUpdate: vi.fn(),
  mockSelect: vi.fn(),
  mockFrom: vi.fn(),
  mockWhere: vi.fn(),
  mockValues: vi.fn(),
  mockReturning: vi.fn(),
  mockSet: vi.fn(),
}));

vi.mock("@/auth", () => ({
  auth: vi.fn(),
  signIn: vi.fn(),
  signOut: vi.fn(),
  handlers: { GET: vi.fn(), POST: vi.fn() },
}));

vi.mock("@/lib/db", () => ({
  db: {
    insert: mocks.mockInsert,
    update: mocks.mockUpdate,
    select: mocks.mockSelect,
  },
