      target,
      interactiveSelector: "a[href]",
      event: { metaKey: true, ctrlKey: false },
      isEditable: true,
      isExplicitActivationGesture,
    });

    expect(suppress).toBe(false);
  });
});

describe("EditorInteractionPolicy extension", () => {
  let editor: Editor;

  afterEach(() => {
    editor?.destroy();
  });

  function getClickHandler(instance: Editor) {
    const plugin = instance.state.plugins.find((candidate) =>
      candidate.key.startsWith("editorInteractionPolicy$")
    );
    return plugin?.props.handleDOMEvents?.click;
  }

  function createClickEvent(
    target: Node,
    options?: { metaKey?: boolean; ctrlKey?: boolean }
  ) {
    const event = new MouseEvent("click", {
      bubbles: true,
      cancelable: true,
      metaKey: options?.metaKey,
      ctrlKey: options?.ctrlKey,
    });
    Object.defineProperty(event, "target", { value: target });
    return event;
  }

  it("should suppress plain link clicks while editing", () => {
    editor = new Editor({
      element: document.createElement("div"),
      extensions: [StarterKit, EditorInteractionPolicy],
      content: {
        type: "doc",
        content: [
          {
            type: "paragraph",
            content: [
              {
                type: "text",
                text: "Example",
                marks: [{ type: "link", attrs: { href: "https://example.com" } }],
              },
            ],
          },
        ],
      },
    });

    const clickHandler = getClickHandler(editor);
    expect(clickHandler).toBeTypeOf("function");

    const link = document.createElement("a");
    link.href = "https://example.com";
    const event = createClickEvent(link);
    const preventDefaultSpy = vi.spyOn(event, "preventDefault");

    const handled = clickHandler?.(editor.view, event);
    expect(handled).toBe(false);
    expect(preventDefaultSpy).toHaveBeenCalledTimes(1);
  });

  it("should allow explicit link activation gestures while editing", () => {
    editor = new Editor({
      element: document.createElement("div"),
      extensions: [StarterKit, EditorInteractionPolicy],
      content: {
        type: "doc",
        content: [{ type: "paragraph", content: [{ type: "text", text: "Example" }] }],
      },
    });

    const clickHandler = getClickHandler(editor);
    expect(clickHandler).toBeTypeOf("function");

    const link = document.createElement("a");
    link.href = "https://example.com";
    const event = createClickEvent(link, { metaKey: true });
    const preventDefaultSpy = vi.spyOn(event, "preventDefault");

    const handled = clickHandler?.(editor.view, event);
    expect(handled).toBe(false);
    expect(preventDefaultSpy).not.toHaveBeenCalled();
  });

  it("should suppress plain clicks for custom interactive elements", () => {
    editor = new Editor({
      element: document.createElement("div"),
      extensions: [StarterKit, EditorInteractionPolicy],
      content: {
        type: "doc",
        content: [{ type: "paragraph", content: [{ type: "text", text: "Test" }] }],
      },
    });

    const clickHandler = getClickHandler(editor);
    expect(clickHandler).toBeTypeOf("function");

    const interactive = document.createElement("span");
    interactive.setAttribute("data-editor-interactive", "true");
    const event = createClickEvent(interactive);
    const preventDefaultSpy = vi.spyOn(event, "preventDefault");

    const handled = clickHandler?.(editor.view, event);
    expect(handled).toBe(false);
    expect(preventDefaultSpy).toHaveBeenCalledTimes(1);
  });
});

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";

type ActivationGesture = Pick<MouseEvent, "metaKey" | "ctrlKey">;

export interface EditorInteractionPolicyOptions {
  interactiveSelectors: readonly string[];
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}

export const editorInteractionPolicyKey = new PluginKey("editorInteractionPolicy");
export const DEFAULT_INTERACTIVE_SELECTORS = [
  "a[href]",
  "[data-editor-interactive='true']",
] as const;

export function isExplicitActivationGesture(
  event: ActivationGesture
): boolean {
  return event.metaKey || event.ctrlKey;
}

export function buildInteractiveSelector(selectors: readonly string[]): string {
  return selectors
    .map((selector) => selector.trim())
    .filter(Boolean)
    .join(",");
}

function resolveEventTargetElement(target: EventTarget | null): Element | null {
  if (target instanceof Element) return target;
  if (target instanceof Node) return target.parentElement;
  return null;
}

export function shouldSuppressInteractiveClick({
  target,
  interactiveSelector,
  event,
  isEditable,
  isExplicitActivationGesture: allowActivation,
}: {
  target: EventTarget | null;
  interactiveSelector: string;
  event: ActivationGesture;
  isEditable: boolean;
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}): boolean {
  if (!isEditable || !interactiveSelector) return false;
  const targetElement = resolveEventTargetElement(target);
  if (!targetElement) return false;

  const interactiveTarget = targetElement.closest(interactiveSelector);
  if (!interactiveTarget) return false;

  return !allowActivation(event);
}

export const EditorInteractionPolicy = Extension.create<EditorInteractionPolicyOptions>(
  {
    name: "editorInteractionPolicy",

    addOptions() {
      return {
        interactiveSelectors: DEFAULT_INTERACTIVE_SELECTORS,
        isExplicitActivationGesture,
      };
    },

    addProseMirrorPlugins() {
      const interactiveSelector = buildInteractiveSelector(
        this.options.interactiveSelectors
      );
      const allowActivation = this.options.isExplicitActivationGesture;

      return [
        new Plugin({
          key: editorInteractionPolicyKey,
          props: {
            handleDOMEvents: {
              click(view, event) {
                if (!(event instanceof MouseEvent)) return false;

                const shouldSuppress = shouldSuppressInteractiveClick({
                  target: event.target,
                  interactiveSelector,
                  event,
                  isEditable: view.editable,
                  isExplicitActivationGesture: allowActivation,
                });

                if (!shouldSuppress) return false;
                event.preventDefault();
                // Let ProseMirror continue processing the click so caret/selection still works.
                return false;
              },
            },
          },
        }),
      ];
    },
  }
);

import { describe, it, expect, afterEach } from "vitest";
import { Editor } from "@tiptap/core";
import StarterKit from "@tiptap/starter-kit";
import { OriginMark } from "./origin-mark";

function createEditor(content?: Record<string, unknown> | string) {
  return new Editor({
    element: document.createElement("div"),
    extensions: [StarterKit, OriginMark],
    content: content ?? { type: "doc", content: [{ type: "paragraph" }] },
  });
}

describe("OriginMark", () => {
  let editor: Editor;

  afterEach(() => {
    editor?.destroy();
  });

  it("should persist through editor JSON serialization/deserialization", () => {
    const docWithMark = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "AI generated text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "interaction-123",
                    originalLength: 17,
                  },
                },
              ],
            },
          ],
        },
      ],
    };

    editor = createEditor(docWithMark);
    const json = editor.getJSON();

    const textNode = json.content?.[0]?.content?.[0];
    expect(textNode?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "ai",
          sourceId: "interaction-123",
          originalLength: 17,
          originalText: null,
        },
      },
    ]);

    // Re-create editor from serialized JSON to verify round-trip
    const editor2 = createEditor(json);
    const json2 = editor2.getJSON();
    const textNode2 = json2.content?.[0]?.content?.[0];
    expect(textNode2?.marks).toEqual(textNode?.marks);
    editor2.destroy();
  });

  it("should preserve attrs through HTML round-trip parsing", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "pasted text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "external_paste",
                    sourceId: "paste-123",
                    originalLength: 11,
                    originalText: "pasted text",
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    const html = editor.getHTML();

    const editor2 = createEditor(html);
    const json2 = editor2.getJSON();
    const textNode2 = json2.content?.[0]?.content?.[0];

    expect(textNode2?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "external_paste",
          sourceId: "paste-123",
          originalLength: 11,
          originalText: "pasted text",
        },
      },
    ]);

    editor2.destroy();
  });

  it("should preserve attrs when editor root class is mutated", () => {
    editor = createEditor({
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            {
              type: "text",
              text: "AI generated text",
              marks: [
                {
                  type: "origin",
                  attrs: {
                    type: "ai",
                    sourceId: "interaction-123",
                    originalLength: 17,
                    originalText: "AI generated text",
                  },
                },
              ],
            },
          ],
        },
      ],
    });

    editor.view.dom.classList.add("lens-off");
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (editor.view as any).domObserver?.flush?.();

    const json = editor.getJSON();
    const textNode = json.content?.[0]?.content?.[0];
    expect(textNode?.marks).toEqual([
      {
        type: "origin",
        attrs: {
          type: "ai",
          sourceId: "interaction-123",
          originalLength: 17,
          originalText: "AI generated text",
        },
      },
    ]);
  });

  it("should apply origin mark with type='ai' and sourceId for AI text insertion", () => {
    editor = createEditor();

    editor
      .chain()
      .focus()
      .insertContent({
        type: "text",
        text: "AI suggestion",
        marks: [
          {
            type: "origin",
            attrs: {
              type: "ai",
              sourceId: "src-abc",
              originalLength: 13,
            },
          },
        ],
      })
      .run();

    const json = editor.getJSON();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const textNode = json.content?.[0]?.content?.[0] as any;
