import { isValidModel } from "./providers";

export type SupportedProvider = "anthropic" | "openai";

interface ResolveProviderModelInput {
  requestedProvider?: string;
  requestedModel?: string;
  storedProvider?: string | null;
  storedModel?: string | null;
}

interface ResolveProviderModelResult {
  provider: SupportedProvider;
  model?: string;
  invalidRequestedModel: boolean;
}

function normalizeProvider(value: string | null | undefined): SupportedProvider | null {
  if (value === "anthropic" || value === "openai") return value;
  return null;
}

function normalizeModel(value: string | null | undefined): string | undefined {
  const trimmed = value?.trim();
  return trimmed ? trimmed : undefined;
}

export function resolveProviderModel(
  input: ResolveProviderModelInput
): ResolveProviderModelResult {
  const requestedProvider = normalizeProvider(input.requestedProvider);
  const storedProvider = normalizeProvider(input.storedProvider);
  const provider = requestedProvider ?? storedProvider ?? "anthropic";

  const requestedModel = normalizeModel(input.requestedModel);
  if (requestedModel) {
    if (!isValidModel(provider, requestedModel)) {
      return { provider, invalidRequestedModel: true };
    }
    return {
      provider,
      model: requestedModel,
      invalidRequestedModel: false,
    };
  }

  const storedModel = normalizeModel(input.storedModel);
  if (storedModel && isValidModel(provider, storedModel)) {
    return {
      provider,
      model: storedModel,
      invalidRequestedModel: false,
    };
  }

  return {
    provider,
    model: undefined,
    invalidRequestedModel: false,
  };
}

import { z } from "zod";

const MAX_MESSAGE_BYTES = 25_000;
const MAX_MESSAGE_PARTS = 200;

function isWithinMessageByteBudget(value: unknown): boolean {
  try {
    const serialized = JSON.stringify(value);
    if (!serialized) return true;
    return new TextEncoder().encode(serialized).length <= MAX_MESSAGE_BYTES;
  } catch {
    return false;
  }
}

const messagePartSchema = z
  .object({
    type: z.string().max(64),
    text: z.string().max(20_000).optional(),
  })
  .passthrough();

const chatMessageSchema = z
  .object({
    id: z.string().max(256).optional(),
    role: z.enum(["user", "assistant", "system", "tool"]),
    content: z
      .union([z.string().max(20_000), z.array(messagePartSchema).max(MAX_MESSAGE_PARTS)])
      .optional(),
    parts: z.array(messagePartSchema).max(MAX_MESSAGE_PARTS).optional(),
  })
  .passthrough()
  .superRefine((value, ctx) => {
    if (!isWithinMessageByteBudget(value)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Message payload too large",
      });
    }
  });

const completionMessageSchema = z
  .object({
    role: z.enum(["user", "assistant", "system", "tool"]),
    content: z
      .union([z.string().max(20_000), z.array(messagePartSchema).max(MAX_MESSAGE_PARTS)])
      .optional(),
    parts: z.array(messagePartSchema).max(MAX_MESSAGE_PARTS).optional(),
  })
  .passthrough()
  .superRefine((value, ctx) => {
    if (!isWithinMessageByteBudget(value)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Message payload too large",
      });
    }
  });

export const chatRequestSchema = z.object({
  provider: z.enum(["anthropic", "openai"]).optional(),
  model: z.string().max(100).optional(),
  messages: z.array(chatMessageSchema).min(1).max(100),
  documentContext: z.string().max(50_000).optional(),
  threadId: z.string().uuid().optional(),
});

export const aiCompletionSchema = z
  .object({
    mode: z.enum(["inline", "side_panel", "freeform"]),
    provider: z.enum(["anthropic", "openai"]).optional(),
    model: z.string().max(100).optional(),
    prompt: z.string().max(10_000).optional(),
    selectedText: z.string().max(10_000).optional(),
    context: z.string().max(100_000).optional(),
    messages: z.array(completionMessageSchema).max(50).optional(),
  })
  .refine((data) => data.prompt || (data.messages && data.messages.length > 0), {
    message: "Either prompt or messages must be provided",
  });

export function getSystemPrompt(
  mode: "inline" | "side_panel" | "freeform" | "chat"
): string {
  switch (mode) {
    case "inline":
      return "You are a writing assistant helping to improve selected text. Provide direct text replacements without explanations or markdown formatting. Match the style and tone of the surrounding content.";
    case "side_panel":
      return "You are a writing assistant with full access to the document context. Help the user with research, brainstorming, and writing suggestions. Be conversational and helpful.";
    case "freeform":
      return "You are a writing assistant. Help the user with their writing request. Provide clear, actionable content that can be inserted into a document.";
    case "chat":
      return "You are a writing assistant embedded in a document editor. You have access to the writer's full document. Help with research, critique, brainstorming, and structural analysis. When critiquing, point to specific parts of the text. Be conversational and direct. Do not rewrite the document — offer observations and suggestions the writer can act on themselves.";
  }
}

import { describe, it, expect } from "vitest";
import { readJsonBody, ReadJsonBodyError } from "./read-json-body";

describe("readJsonBody", () => {
  it("should parse valid JSON body", async () => {
    const req = new Request("http://localhost", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ hello: "world" }),
    });

    const parsed = await readJsonBody(req, 1024);
    expect(parsed).toEqual({ hello: "world" });
  });

  it("should reject invalid JSON", async () => {
    const req = new Request("http://localhost", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: "{bad json",
    });

    await expect(readJsonBody(req, 1024)).rejects.toEqual(
      expect.objectContaining<Partial<ReadJsonBodyError>>({
        status: 400,
      })
    );
  });

  it("should reject oversized body via content-length", async () => {
    const req = new Request("http://localhost", {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "content-length": "9999",
      },
      body: JSON.stringify({ ok: true }),
    });

    await expect(readJsonBody(req, 1024)).rejects.toEqual(
      expect.objectContaining<Partial<ReadJsonBodyError>>({
        status: 413,
      })
    );
  });
});

export class ReadJsonBodyError extends Error {
  readonly status: number;

  constructor(status: number, message: string) {
    super(message);
    this.status = status;
  }
}

export async function readJsonBody(
  req: Request,
  maxBytes: number
): Promise<unknown> {
  const contentLength = req.headers.get("content-length");
  if (contentLength) {
    const size = Number(contentLength);
    if (Number.isFinite(size) && size > maxBytes) {
      throw new ReadJsonBodyError(413, "Request body too large");
    }
  }

  const bodyText = await req.text();
  const bodyBytes = new TextEncoder().encode(bodyText).length;
  if (bodyBytes > maxBytes) {
    throw new ReadJsonBodyError(413, "Request body too large");
  }

  if (!bodyText.trim()) {
    throw new ReadJsonBodyError(400, "Request body is required");
  }

  try {
    return JSON.parse(bodyText);
  } catch {
    throw new ReadJsonBodyError(400, "Invalid JSON body");
  }
}

