      const days = groupEventsByDay(events);
      expect(days).toHaveLength(2);
      expect(days[0].date).toBe("2025-01-15");
      expect(days[1].date).toBe("2025-01-16");
    });

    it("should handle empty events array", () => {
      const days = groupEventsByDay([]);
      expect(days).toHaveLength(0);
    });

    it("should group events into sessions within a day", () => {
      const events = [
        { type: "session_start" as const, timestamp: "2025-01-15T10:00:00Z", data: {} },
        { type: "ai_interaction" as const, timestamp: "2025-01-15T10:05:00Z", data: {} },
        { type: "session_end" as const, timestamp: "2025-01-15T10:30:00Z", data: {} },
      ];

      const days = groupEventsByDay(events);
      expect(days).toHaveLength(1);
      expect(days[0].sessions).toHaveLength(1);
      expect(days[0].sessions[0].events).toHaveLength(1);
      expect(days[0].sessions[0].events[0].type).toBe("ai_interaction");
    });
  });

  describe("clusterRevisions", () => {
    it("should cluster 3+ consecutive revisions into a single entry", () => {
      const events = [
        { type: "revision" as const, timestamp: "2025-01-15T10:00:00Z", data: {} },
        { type: "revision" as const, timestamp: "2025-01-15T10:05:00Z", data: {} },
        { type: "revision" as const, timestamp: "2025-01-15T10:10:00Z", data: {} },
        { type: "revision" as const, timestamp: "2025-01-15T10:15:00Z", data: {} },
      ];

      const result = clusterRevisions(events);
      expect(result).toHaveLength(1);
      expect("count" in result[0]).toBe(true);
      if ("count" in result[0]) {
        expect(result[0].count).toBe(4);
        expect(result[0].durationMinutes).toBe(15);
      }
    });

    it("should keep 1-2 revisions as individual events", () => {
      const events = [
        { type: "revision" as const, timestamp: "2025-01-15T10:00:00Z", data: {} },
        { type: "revision" as const, timestamp: "2025-01-15T10:05:00Z", data: {} },
      ];

      const result = clusterRevisions(events);
      expect(result).toHaveLength(2);
    });

    it("should keep non-revision events as-is", () => {
      const events = [
        { type: "ai_interaction" as const, timestamp: "2025-01-15T10:00:00Z", data: {} },
        { type: "paste" as const, timestamp: "2025-01-15T10:05:00Z", data: {} },
      ];

      const result = clusterRevisions(events);
      expect(result).toHaveLength(2);
    });
  });

  describe("getEventCounts", () => {
    it("should count events by type", () => {
      const events = [
        { type: "ai_interaction" as const, timestamp: "2025-01-15T10:00:00Z", data: {} },
        { type: "ai_interaction" as const, timestamp: "2025-01-15T10:05:00Z", data: {} },
        { type: "paste" as const, timestamp: "2025-01-15T11:00:00Z", data: {} },
        { type: "revision" as const, timestamp: "2025-01-15T11:05:00Z", data: {} },
      ];

      const counts = getEventCounts(events);
      expect(counts.ai_interaction).toBe(2);
      expect(counts.paste).toBe(1);
      expect(counts.revision).toBe(1);
    });
  });
});

interface RawEvent {
  type: "ai_interaction" | "paste" | "session_start" | "session_end" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface DayGroup {
  date: string; // YYYY-MM-DD
  label: string; // "Jan 15, 2025"
  sessions: SessionGroup[];
}

export interface SessionGroup {
  startTime: string | null;
  endTime: string | null;
  events: TimelineEvent[];
}

export interface TimelineEvent {
  type: "ai_interaction" | "paste" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface RevisionCluster {
  count: number;
  startTime: string | Date | null;
  endTime: string | Date | null;
  durationMinutes: number;
}

function toDateKey(ts: string | Date | null): string {
  if (!ts) return "unknown";
  const d = new Date(ts);
  return d.toISOString().split("T")[0];
}

function formatDateLabel(dateKey: string): string {
  if (dateKey === "unknown") return "Unknown Date";
  const d = new Date(dateKey + "T00:00:00");
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

export function groupEventsByDay(events: RawEvent[]): DayGroup[] {
  const dayMap = new Map<string, RawEvent[]>();

  for (const event of events) {
    const key = toDateKey(event.timestamp);
    if (!dayMap.has(key)) dayMap.set(key, []);
    dayMap.get(key)!.push(event);
  }

  const days: DayGroup[] = [];
  const sortedKeys = [...dayMap.keys()].sort();

  for (const key of sortedKeys) {
    const dayEvents = dayMap.get(key)!;
    days.push({
      date: key,
      label: formatDateLabel(key),
      sessions: groupIntoSessions(dayEvents),
    });
  }

  return days;
}

function groupIntoSessions(events: RawEvent[]): SessionGroup[] {
  // Find session boundaries
  const sessionStarts = events.filter((e) => e.type === "session_start");
  const nonSessionEvents = events.filter(
    (e) => e.type !== "session_start" && e.type !== "session_end"
  );

  if (sessionStarts.length === 0) {
    // No sessions, put all events in a single group
    return [{
      startTime: nonSessionEvents[0]?.timestamp?.toString() ?? null,
      endTime: nonSessionEvents[nonSessionEvents.length - 1]?.timestamp?.toString() ?? null,
      events: nonSessionEvents.map((e) => ({
        type: e.type as TimelineEvent["type"],
        timestamp: e.timestamp,
        data: e.data,
      })),
    }];
  }

  // Group events by session
  const sessions: SessionGroup[] = [];
  const sorted = [...events].sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });

  let currentSession: SessionGroup | null = null;

  for (const event of sorted) {
    if (event.type === "session_start") {
      if (currentSession) sessions.push(currentSession);
      currentSession = {
        startTime: event.timestamp?.toString() ?? null,
        endTime: null,
        events: [],
      };
    } else if (event.type === "session_end") {
      if (currentSession) {
        currentSession.endTime = event.timestamp?.toString() ?? null;
        sessions.push(currentSession);
        currentSession = null;
      }
    } else {
      if (!currentSession) {
        currentSession = {
          startTime: event.timestamp?.toString() ?? null,
          endTime: null,
          events: [],
        };
      }
      currentSession.events.push({
        type: event.type as TimelineEvent["type"],
        timestamp: event.timestamp,
        data: event.data,
      });
    }
  }

  if (currentSession) sessions.push(currentSession);

  return sessions;
}

export function clusterRevisions(events: TimelineEvent[]): (TimelineEvent | RevisionCluster)[] {
  const result: (TimelineEvent | RevisionCluster)[] = [];
  let revisionBuffer: TimelineEvent[] = [];

  const flushRevisions = () => {
    if (revisionBuffer.length === 0) return;
    if (revisionBuffer.length <= 2) {
      result.push(...revisionBuffer);
    } else {
      const first = revisionBuffer[0].timestamp;
      const last = revisionBuffer[revisionBuffer.length - 1].timestamp;
      const startMs = first ? new Date(first).getTime() : 0;
      const endMs = last ? new Date(last).getTime() : 0;
      result.push({
        count: revisionBuffer.length,
        startTime: first,
        endTime: last,
        durationMinutes: Math.round((endMs - startMs) / 60000),
      });
    }
    revisionBuffer = [];
  };

  for (const event of events) {
    if (event.type === "revision") {
      revisionBuffer.push(event);
    } else {
      flushRevisions();
      result.push(event);
    }
  }
  flushRevisions();

  return result;
}

export function getEventCounts(events: RawEvent[]): Record<string, number> {
  const counts: Record<string, number> = {
    ai_interaction: 0,
    paste: 0,
    revision: 0,
  };

  for (const event of events) {
    if (event.type in counts) {
      counts[event.type]++;
    }
  }

  return counts;
}

import { describe, it, expect } from "vitest";
import { extractPlainText } from "./tiptap-utils";

describe("extractPlainText", () => {
  it("should extract text from a simple paragraph", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: "Hello world" }],
        },
      ],
    };

    expect(extractPlainText(doc)).toBe("Hello world");
  });

  it("should extract text from multiple paragraphs with newlines", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: "First paragraph" }],
        },
        {
          type: "paragraph",
          content: [{ type: "text", text: "Second paragraph" }],
        },
      ],
    };

    expect(extractPlainText(doc)).toBe("First paragraph\nSecond paragraph");
  });

  it("should handle nested content with marks", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "paragraph",
          content: [
            { type: "text", text: "Normal " },
            {
              type: "text",
              text: "bold",
              marks: [{ type: "bold" }],
            },
            { type: "text", text: " text" },
          ],
        },
      ],
    };

    expect(extractPlainText(doc)).toBe("Normal bold text");
  });

  it("should handle headings", () => {
    const doc = {
      type: "doc",
      content: [
        {
          type: "heading",
          attrs: { level: 1 },
          content: [{ type: "text", text: "Title" }],
        },
        {
          type: "paragraph",
          content: [{ type: "text", text: "Content" }],
        },
      ],
    };

    expect(extractPlainText(doc)).toBe("Title\nContent");
  });

  it("should handle empty document", () => {
    const doc = {
      type: "doc",
      content: [{ type: "paragraph" }],
    };

    expect(extractPlainText(doc)).toBe("");
  });

  it("should handle document with no content", () => {
    const doc = { type: "doc" };
    expect(extractPlainText(doc)).toBe("");
  });
});

interface TipTapNode {
  type?: string;
  text?: string;
  content?: TipTapNode[];
  marks?: { type: string; attrs?: Record<string, unknown> }[];
}

export function extractPlainText(doc: TipTapNode): string {
  const parts: string[] = [];

  function walk(node: TipTapNode) {
    if (node.text) {
      parts.push(node.text);
      return;
    }

    if (node.content) {
      for (const child of node.content) {
        walk(child);
      }

      // Add newline after block-level nodes (paragraph, heading, etc.)
      if (
        node.type &&
        node.type !== "doc" &&
        node.type !== "text" &&
        parts.length > 0
      ) {
        parts.push("\n");
      }
    }
  }

  walk(doc);

  return parts.join("").trim();
}

